/**
 * Service to list problems with filtering, paging, sorting, and metadata.
 * @param {Object} options
 * @param {string[]} [options.difficulty] - Array of difficulty strings to filter by.
 * @param {boolean} [options.includeComponents] - Whether to include sorted componentLanguages array.
 * @returns {Object} - { problems, totalProblems, filteredCount, appliedLimit, difficultyBreakdown }
 */
async function listProblems({ difficulty, includeComponents } = {}) {
  // Normalize difficulty filter to a Set for quick lookup if provided
  const difficultyFilter = Array.isArray(difficulty) && difficulty.length > 0 ? new Set(difficulty) : null;

  // Total problems count
  const totalProblems = problemsData.length;

  // Filter problems by difficulty if filter is applied
  let filteredProblems = problemsData;
  if (difficultyFilter) {
    filteredProblems = problemsData.filter(p => difficultyFilter.has(p.difficulty));
  }

  // filteredCount before limit
  const filteredCount = filteredProblems.length;

  // Enforce paging limit of 50 results
  const appliedLimit = 50;
  filteredProblems = filteredProblems.slice(0, appliedLimit);

  // Sort problems by roundId ascending (deterministic ordering)
  filteredProblems.sort((a, b) => {
    if (a.roundId < b.roundId) return -1;
    if (a.roundId > b.roundId) return 1;
    return 0;
  });

  // If includeComponents is true, add sorted componentLanguages array
  if (includeComponents) {
    filteredProblems = filteredProblems.map(p => {
      // Defensive: if componentLanguages exists and is array
      const compLangs = Array.isArray(p.componentLanguages) ? [...p.componentLanguages].sort() : [];
      return {
        ...p,
        componentLanguages: compLangs
      };
    });
  }

  // Compute difficultyBreakdown for filtered problems (before limit)
  const difficultyBreakdown = {};
  for (const p of difficultyFilter ? problemsData.filter(p => difficultyFilter.has(p.difficulty)) : problemsData) {
    difficultyBreakdown[p.difficulty] = (difficultyBreakdown[p.difficulty] || 0) + 1;
  }

  return {
    problems: filteredProblems,
    totalProblems,
    filteredCount,
    appliedLimit,
    difficultyBreakdown
  };
}

module.exports = {
  listProblems
};
